INSERT INTO ChangeEntities VALUES(0,'{{seed-commit-morph-types}}','D7F713E4-E8CF-11D3-9764-00C04F186933','{"$type":"CreateMorphTypeChange","Name":{"en":"bound root"},"Abbreviation":{"en":"bd root"},"Description":{"en":{"Spans":[{"Text":"A bound root is a root which cannot occur as a separate word apart from any other morpheme.","Ws":"en"}]}},"Prefix":"*","Postfix":null,"SecondaryOrder":10,"Kind":"BoundRoot","EntityId":"d7f713e4-e8cf-11d3-9764-00c04f186933"}');
INSERT INTO ChangeEntities VALUES(1,'{{seed-commit-morph-types}}','D7F713E7-E8CF-11D3-9764-00C04F186933','{"$type":"CreateMorphTypeChange","Name":{"en":"bound stem"},"Abbreviation":{"en":"bd stem"},"Description":{"en":{"Spans":[{"Text":"A bound stem is a stem which cannot occur as a separate word apart from any other morpheme.","Ws":"en"}]}},"Prefix":"*","Postfix":null,"SecondaryOrder":10,"Kind":"BoundStem","EntityId":"d7f713e7-e8cf-11d3-9764-00c04f186933"}');
INSERT INTO ChangeEntities VALUES(2,'{{seed-commit-morph-types}}','D7F713DF-E8CF-11D3-9764-00C04F186933','{"$type":"CreateMorphTypeChange","Name":{"en":"circumfix"},"Abbreviation":{"en":"cfx"},"Description":{"en":{"Spans":[{"Text":"A circumfix is an affix made up of two separate parts which surround and attach to a root or stem.","Ws":"en"}]}},"Prefix":null,"Postfix":null,"SecondaryOrder":0,"Kind":"Circumfix","EntityId":"d7f713df-e8cf-11d3-9764-00c04f186933"}');
INSERT INTO ChangeEntities VALUES(3,'{{seed-commit-morph-types}}','C2D140E5-7CA9-41F4-A69A-22FC7049DD2C','{"$type":"CreateMorphTypeChange","Name":{"en":"clitic"},"Abbreviation":{"en":"clit"},"Description":{"en":{"Spans":[{"Text":"A clitic is a morpheme that has syntactic characteristics of a word, but shows evidence of being phonologically bound to another word. Orthographically, it stands alone.","Ws":"en"}]}},"Prefix":null,"Postfix":null,"SecondaryOrder":0,"Kind":"Clitic","EntityId":"c2d140e5-7ca9-41f4-a69a-22fc7049dd2c"}');
INSERT INTO ChangeEntities VALUES(4,'{{seed-commit-morph-types}}','D7F713E1-E8CF-11D3-9764-00C04F186933','{"$type":"CreateMorphTypeChange","Name":{"en":"enclitic"},"Abbreviation":{"en":"enclit"},"Description":{"en":{"Spans":[{"Text":"An enclitic is a clitic that is phonologically joined at the end of a preceding word to form a single unit. Orthographically, it may attach to the preceding word.","Ws":"en"}]}},"Prefix":"=","Postfix":null,"SecondaryOrder":80,"Kind":"Enclitic","EntityId":"d7f713e1-e8cf-11d3-9764-00c04f186933"}');
INSERT INTO ChangeEntities VALUES(5,'{{seed-commit-morph-types}}','D7F713DA-E8CF-11D3-9764-00C04F186933','{"$type":"CreateMorphTypeChange","Name":{"en":"infix"},"Abbreviation":{"en":"ifx"},"Description":{"en":{"Spans":[{"Text":"An infix is an affix that is inserted within a root or stem.","Ws":"en"}]}},"Prefix":"-","Postfix":"-","SecondaryOrder":40,"Kind":"Infix","EntityId":"d7f713da-e8cf-11d3-9764-00c04f186933"}');
INSERT INTO ChangeEntities VALUES(6,'{{seed-commit-morph-types}}','56DB04BF-3D58-44CC-B292-4C8AA68538F4','{"$type":"CreateMorphTypeChange","Name":{"en":"particle"},"Abbreviation":{"en":"part"},"Description":{"en":{"Spans":[{"Text":"A particle is a word that does not belong to one of the main classes of words, is invariable in form, and typically has grammatical or pragmatic meaning.","Ws":"en"}]}},"Prefix":null,"Postfix":null,"SecondaryOrder":0,"Kind":"Particle","EntityId":"56db04bf-3d58-44cc-b292-4c8aa68538f4"}');
INSERT INTO ChangeEntities VALUES(7,'{{seed-commit-morph-types}}','D7F713DB-E8CF-11D3-9764-00C04F186933','{"$type":"CreateMorphTypeChange","Name":{"en":"prefix"},"Abbreviation":{"en":"pfx"},"Description":{"en":{"Spans":[{"Text":"A prefix is an affix that is joined before a root or stem.","Ws":"en"}]}},"Prefix":null,"Postfix":"-","SecondaryOrder":20,"Kind":"Prefix","EntityId":"d7f713db-e8cf-11d3-9764-00c04f186933"}');
INSERT INTO ChangeEntities VALUES(8,'{{seed-commit-morph-types}}','D7F713E2-E8CF-11D3-9764-00C04F186933','{"$type":"CreateMorphTypeChange","Name":{"en":"proclitic"},"Abbreviation":{"en":"proclit"},"Description":{"en":{"Spans":[{"Text":"A proclitic is a clitic that precedes the word to which it is phonologically joined. Orthographically, it may attach to the following word.","Ws":"en"}]}},"Prefix":null,"Postfix":"=","SecondaryOrder":30,"Kind":"Proclitic","EntityId":"d7f713e2-e8cf-11d3-9764-00c04f186933"}');
INSERT INTO ChangeEntities VALUES(9,'{{seed-commit-morph-types}}','D7F713E5-E8CF-11D3-9764-00C04F186933','{"$type":"CreateMorphTypeChange","Name":{"en":"root"},"Abbreviation":{"en":"ubd root"},"Description":{"en":{"Spans":[{"Text":"A root is the portion of a word that (i) is common to a set of derived or inflected forms, if any, when all affixes are removed, (ii) is not further analyzable into meaningful elements, being morphologically simple, and, (iii) carries the principal portion of meaning of the words in which it functions.","Ws":"en"}]}},"Prefix":null,"Postfix":null,"SecondaryOrder":0,"Kind":"Root","EntityId":"d7f713e5-e8cf-11d3-9764-00c04f186933"}');
INSERT INTO ChangeEntities VALUES(10,'{{seed-commit-morph-types}}','D7F713DC-E8CF-11D3-9764-00C04F186933','{"$type":"CreateMorphTypeChange","Name":{"en":"simulfix"},"Abbreviation":{"en":"smfx"},"Description":{"en":{"Spans":[{"Text":"A simulfix is a change or replacement of vowels or consonants (usually vowels) which changes the meaning of a word. (Note: the parser does not currently handle simulfixes.)","Ws":"en"}]}},"Prefix":"=","Postfix":"=","SecondaryOrder":60,"Kind":"Simulfix","EntityId":"d7f713dc-e8cf-11d3-9764-00c04f186933"}');
INSERT INTO ChangeEntities VALUES(11,'{{seed-commit-morph-types}}','D7F713E8-E8CF-11D3-9764-00C04F186933','{"$type":"CreateMorphTypeChange","Name":{"en":"stem"},"Abbreviation":{"en":"ubd stem"},"Description":{"en":{"Spans":[{"Text":"\u0022A stem is the root or roots of a word, together with any derivational affixes, to which inflectional affixes are added.\u0022 (LinguaLinks Library). A stem \u0022may consist solely of a single root morpheme (i.e. a \u0027simple\u0027 stem as in ","Ws":"en"},{"Text":"man","Ws":"en","NamedStyle":"Emphasized Text"},{"Text":"), or of two root morphemes (e.g. a \u0027compound\u0027 stem, as in ","Ws":"en"},{"Text":"blackbird","Ws":"en","NamedStyle":"Emphasized Text"},{"Text":"), or of a root morpheme plus a derivational affix (i.e. a \u0027complex\u0027 stem, as in ","Ws":"en"},{"Text":"manly","Ws":"en","NamedStyle":"Emphasized Text"},{"Text":", ","Ws":"en"},{"Text":"unmanly","Ws":"en","NamedStyle":"Emphasized Text"},{"Text":", ","Ws":"en"},{"Text":"manliness","Ws":"en","NamedStyle":"Emphasized Text"},{"Text":"). All have in common the notion that it is to the stem that inflectional affixes are attached.\u0022 (Crystal, 1997:362)","Ws":"en"}]}},"Prefix":null,"Postfix":null,"SecondaryOrder":0,"Kind":"Stem","EntityId":"d7f713e8-e8cf-11d3-9764-00c04f186933"}');
INSERT INTO ChangeEntities VALUES(12,'{{seed-commit-morph-types}}','D7F713DD-E8CF-11D3-9764-00C04F186933','{"$type":"CreateMorphTypeChange","Name":{"en":"suffix"},"Abbreviation":{"en":"sfx"},"Description":{"en":{"Spans":[{"Text":"A suffix is an affix that is attached to the end of a root or stem.","Ws":"en"}]}},"Prefix":"-","Postfix":null,"SecondaryOrder":70,"Kind":"Suffix","EntityId":"d7f713dd-e8cf-11d3-9764-00c04f186933"}');
INSERT INTO ChangeEntities VALUES(13,'{{seed-commit-morph-types}}','D7F713DE-E8CF-11D3-9764-00C04F186933','{"$type":"CreateMorphTypeChange","Name":{"en":"suprafix"},"Abbreviation":{"en":"spfx"},"Description":{"en":{"Spans":[{"Text":"A suprafix is a kind of affix in which a suprasegmental is superimposed on one or more syllables of the root or stem, signalling a particular morphosyntactic operation. (Note: the parser does not currently handle suprafixes.)","Ws":"en"}]}},"Prefix":"~","Postfix":"~","SecondaryOrder":50,"Kind":"Suprafix","EntityId":"d7f713de-e8cf-11d3-9764-00c04f186933"}');
INSERT INTO ChangeEntities VALUES(14,'{{seed-commit-morph-types}}','18D9B1C3-B5B6-4C07-B92C-2FE1D2281BD4','{"$type":"CreateMorphTypeChange","Name":{"en":"infixing interfix"},"Abbreviation":{"en":"ifxnfx"},"Description":{"en":{"Spans":[{"Text":"An infixing interfix is an infix that can occur between two roots or stems.","Ws":"en"}]}},"Prefix":"-","Postfix":"-","SecondaryOrder":0,"Kind":"InfixingInterfix","EntityId":"18d9b1c3-b5b6-4c07-b92c-2fe1d2281bd4"}');
INSERT INTO ChangeEntities VALUES(15,'{{seed-commit-morph-types}}','AF6537B0-7175-4387-BA6A-36547D37FB13','{"$type":"CreateMorphTypeChange","Name":{"en":"prefixing interfix"},"Abbreviation":{"en":"pfxnfx"},"Description":{"en":{"Spans":[{"Text":"A prefixing interfix is a prefix that can occur between two roots or stems.","Ws":"en"}]}},"Prefix":null,"Postfix":"-","SecondaryOrder":0,"Kind":"PrefixingInterfix","EntityId":"af6537b0-7175-4387-ba6a-36547d37fb13"}');
INSERT INTO ChangeEntities VALUES(16,'{{seed-commit-morph-types}}','3433683D-08A9-4BAE-AE53-2A7798F64068','{"$type":"CreateMorphTypeChange","Name":{"en":"suffixing interfix"},"Abbreviation":{"en":"sfxnfx"},"Description":{"en":{"Spans":[{"Text":"A suffixing interfix is a suffix that can occur between two roots or stems.","Ws":"en"}]}},"Prefix":"-","Postfix":null,"SecondaryOrder":0,"Kind":"SuffixingInterfix","EntityId":"3433683d-08a9-4bae-ae53-2a7798f64068"}');
INSERT INTO ChangeEntities VALUES(17,'{{seed-commit-morph-types}}','A23B6FAA-1052-4F4D-984B-4B338BDAF95F','{"$type":"CreateMorphTypeChange","Name":{"en":"phrase"},"Abbreviation":{"en":"phr"},"Description":{"en":{"Spans":[{"Text":"A phrase is a syntactic structure that consists of more than one word but lacks the subject-predicate organization of a clause.","Ws":"en"}]}},"Prefix":null,"Postfix":null,"SecondaryOrder":0,"Kind":"Phrase","EntityId":"a23b6faa-1052-4f4d-984b-4b338bdaf95f"}');
INSERT INTO ChangeEntities VALUES(18,'{{seed-commit-morph-types}}','0CC8C35A-CEE9-434D-BE58-5D29130FBA5B','{"$type":"CreateMorphTypeChange","Name":{"en":"discontiguous phrase"},"Abbreviation":{"en":"dis phr"},"Description":{"en":{"Spans":[{"Text":"A discontiguous phrase has discontiguous constituents which (a) are separated from each other by one or more intervening constituents, and (b) are considered either (i) syntactically contiguous and unitary, or (ii) realizing the same, single meaning. An example is French ne...pas.","Ws":"en"}]}},"Prefix":null,"Postfix":null,"SecondaryOrder":0,"Kind":"DiscontiguousPhrase","EntityId":"0cc8c35a-cee9-434d-be58-5d29130fba5b"}');
