INSERT INTO Snapshots VALUES('Guid_54','MorphType','{"$type":"MiniLcmCrdtAdapter","Obj":{"$type":"MorphType","Id":"c2d140e5-7ca9-41f4-a69a-22fc7049dd2c","Kind":"Clitic","Name":{"en":"clitic"},"Abbreviation":{"en":"clit"},"Description":{"en":{"Spans":[{"Text":"A clitic is a morpheme that has syntactic characteristics of a word, but shows evidence of being phonologically bound to another word. Orthographically, it stands alone.","Ws":"en"}]}},"Prefix":null,"Postfix":null,"SecondaryOrder":0,"DeletedAt":null},"Id":"c2d140e5-7ca9-41f4-a69a-22fc7049dd2c","DeletedAt":null}','[]','C2D140E5-7CA9-41F4-A69A-22FC7049DD2C',0,'{{seed-commit-morph-types}}',1);
INSERT INTO Snapshots VALUES('Guid_55','MorphType','{"$type":"MiniLcmCrdtAdapter","Obj":{"$type":"MorphType","Id":"d7f713e8-e8cf-11d3-9764-00c04f186933","Kind":"Stem","Name":{"en":"stem"},"Abbreviation":{"en":"ubd stem"},"Description":{"en":{"Spans":[{"Text":"\u0022A stem is the root or roots of a word, together with any derivational affixes, to which inflectional affixes are added.\u0022 (LinguaLinks Library). A stem \u0022may consist solely of a single root morpheme (i.e. a \u0027simple\u0027 stem as in ","Ws":"en"},{"Text":"man","Ws":"en","NamedStyle":"Emphasized Text"},{"Text":"), or of two root morphemes (e.g. a \u0027compound\u0027 stem, as in ","Ws":"en"},{"Text":"blackbird","Ws":"en","NamedStyle":"Emphasized Text"},{"Text":"), or of a root morpheme plus a derivational affix (i.e. a \u0027complex\u0027 stem, as in ","Ws":"en"},{"Text":"manly","Ws":"en","NamedStyle":"Emphasized Text"},{"Text":", ","Ws":"en"},{"Text":"unmanly","Ws":"en","NamedStyle":"Emphasized Text"},{"Text":", ","Ws":"en"},{"Text":"manliness","Ws":"en","NamedStyle":"Emphasized Text"},{"Text":"). All have in common the notion that it is to the stem that inflectional affixes are attached.\u0022 (Crystal, 1997:362)","Ws":"en"}]}},"Prefix":null,"Postfix":null,"SecondaryOrder":0,"DeletedAt":null},"Id":"d7f713e8-e8cf-11d3-9764-00c04f186933","DeletedAt":null}','[]','D7F713E8-E8CF-11D3-9764-00C04F186933',0,'{{seed-commit-morph-types}}',1);
