INSERT INTO MorphType VALUES('0CC8C35A-CEE9-434D-BE58-5D29130FBA5B',19,'{"en":"discontiguous phrase"}','{"en":"dis phr"}','{"en":{"Spans":[{"Text":"A discontiguous phrase has discontiguous constituents which (a) are separated from each other by one or more intervening constituents, and (b) are considered either (i) syntactically contiguous and unitary, or (ii) realizing the same, single meaning. An example is French ne...pas.","Ws":"en"}]}}',NULL,NULL,0,NULL,'Guid_41');
INSERT INTO MorphType VALUES('18D9B1C3-B5B6-4C07-B92C-2FE1D2281BD4',15,'{"en":"infixing interfix"}','{"en":"ifxnfx"}','{"en":{"Spans":[{"Text":"An infixing interfix is an infix that can occur between two roots or stems.","Ws":"en"}]}}','-','-',0,NULL,'Guid_45');
INSERT INTO MorphType VALUES('3433683D-08A9-4BAE-AE53-2A7798F64068',17,'{"en":"suffixing interfix"}','{"en":"sfxnfx"}','{"en":{"Spans":[{"Text":"A suffixing interfix is a suffix that can occur between two roots or stems.","Ws":"en"}]}}','-',NULL,0,NULL,'Guid_50');
INSERT INTO MorphType VALUES('56DB04BF-3D58-44CC-B292-4C8AA68538F4',7,'{"en":"particle"}','{"en":"part"}','{"en":{"Spans":[{"Text":"A particle is a word that does not belong to one of the main classes of words, is invariable in form, and typically has grammatical or pragmatic meaning.","Ws":"en"}]}}',NULL,NULL,0,NULL,'Guid_42');
INSERT INTO MorphType VALUES('A23B6FAA-1052-4F4D-984B-4B338BDAF95F',18,'{"en":"phrase"}','{"en":"phr"}','{"en":{"Spans":[{"Text":"A phrase is a syntactic structure that consists of more than one word but lacks the subject-predicate organization of a clause.","Ws":"en"}]}}',NULL,NULL,0,NULL,'Guid_52');
INSERT INTO MorphType VALUES('AF6537B0-7175-4387-BA6A-36547D37FB13',16,'{"en":"prefixing interfix"}','{"en":"pfxnfx"}','{"en":{"Spans":[{"Text":"A prefixing interfix is a prefix that can occur between two roots or stems.","Ws":"en"}]}}',NULL,'-',0,NULL,'Guid_40');
INSERT INTO MorphType VALUES('C2D140E5-7CA9-41F4-A69A-22FC7049DD2C',4,'{"en":"clitic"}','{"en":"clit"}','{"en":{"Spans":[{"Text":"A clitic is a morpheme that has syntactic characteristics of a word, but shows evidence of being phonologically bound to another word. Orthographically, it stands alone.","Ws":"en"}]}}',NULL,NULL,0,NULL,'Guid_54');
INSERT INTO MorphType VALUES('D7F713DA-E8CF-11D3-9764-00C04F186933',6,'{"en":"infix"}','{"en":"ifx"}','{"en":{"Spans":[{"Text":"An infix is an affix that is inserted within a root or stem.","Ws":"en"}]}}','-','-',40,NULL,'Guid_48');
INSERT INTO MorphType VALUES('D7F713DB-E8CF-11D3-9764-00C04F186933',8,'{"en":"prefix"}','{"en":"pfx"}','{"en":{"Spans":[{"Text":"A prefix is an affix that is joined before a root or stem.","Ws":"en"}]}}',NULL,'-',20,NULL,'Guid_53');
INSERT INTO MorphType VALUES('D7F713DC-E8CF-11D3-9764-00C04F186933',11,'{"en":"simulfix"}','{"en":"smfx"}','{"en":{"Spans":[{"Text":"A simulfix is a change or replacement of vowels or consonants (usually vowels) which changes the meaning of a word. (Note: the parser does not currently handle simulfixes.)","Ws":"en"}]}}','=','=',60,NULL,'Guid_51');
INSERT INTO MorphType VALUES('D7F713DD-E8CF-11D3-9764-00C04F186933',13,'{"en":"suffix"}','{"en":"sfx"}','{"en":{"Spans":[{"Text":"A suffix is an affix that is attached to the end of a root or stem.","Ws":"en"}]}}','-',NULL,70,NULL,'Guid_46');
INSERT INTO MorphType VALUES('D7F713DE-E8CF-11D3-9764-00C04F186933',14,'{"en":"suprafix"}','{"en":"spfx"}','{"en":{"Spans":[{"Text":"A suprafix is a kind of affix in which a suprasegmental is superimposed on one or more syllables of the root or stem, signalling a particular morphosyntactic operation. (Note: the parser does not currently handle suprafixes.)","Ws":"en"}]}}','~','~',50,NULL,'Guid_49');
INSERT INTO MorphType VALUES('D7F713DF-E8CF-11D3-9764-00C04F186933',3,'{"en":"circumfix"}','{"en":"cfx"}','{"en":{"Spans":[{"Text":"A circumfix is an affix made up of two separate parts which surround and attach to a root or stem.","Ws":"en"}]}}',NULL,NULL,0,NULL,'Guid_39');
INSERT INTO MorphType VALUES('D7F713E1-E8CF-11D3-9764-00C04F186933',5,'{"en":"enclitic"}','{"en":"enclit"}','{"en":{"Spans":[{"Text":"An enclitic is a clitic that is phonologically joined at the end of a preceding word to form a single unit. Orthographically, it may attach to the preceding word.","Ws":"en"}]}}','=',NULL,80,NULL,'Guid_44');
INSERT INTO MorphType VALUES('D7F713E2-E8CF-11D3-9764-00C04F186933',9,'{"en":"proclitic"}','{"en":"proclit"}','{"en":{"Spans":[{"Text":"A proclitic is a clitic that precedes the word to which it is phonologically joined. Orthographically, it may attach to the following word.","Ws":"en"}]}}',NULL,'=',30,NULL,'Guid_38');
INSERT INTO MorphType VALUES('D7F713E4-E8CF-11D3-9764-00C04F186933',1,'{"en":"bound root"}','{"en":"bd root"}','{"en":{"Spans":[{"Text":"A bound root is a root which cannot occur as a separate word apart from any other morpheme.","Ws":"en"}]}}','*',NULL,10,NULL,'Guid_37');
INSERT INTO MorphType VALUES('D7F713E5-E8CF-11D3-9764-00C04F186933',10,'{"en":"root"}','{"en":"ubd root"}','{"en":{"Spans":[{"Text":"A root is the portion of a word that (i) is common to a set of derived or inflected forms, if any, when all affixes are removed, (ii) is not further analyzable into meaningful elements, being morphologically simple, and, (iii) carries the principal portion of meaning of the words in which it functions.","Ws":"en"}]}}',NULL,NULL,0,NULL,'Guid_47');
INSERT INTO MorphType VALUES('D7F713E7-E8CF-11D3-9764-00C04F186933',2,'{"en":"bound stem"}','{"en":"bd stem"}','{"en":{"Spans":[{"Text":"A bound stem is a stem which cannot occur as a separate word apart from any other morpheme.","Ws":"en"}]}}','*',NULL,10,NULL,'Guid_43');
INSERT INTO MorphType VALUES('D7F713E8-E8CF-11D3-9764-00C04F186933',12,'{"en":"stem"}','{"en":"ubd stem"}','{"en":{"Spans":[{"Text":"\u0022A stem is the root or roots of a word, together with any derivational affixes, to which inflectional affixes are added.\u0022 (LinguaLinks Library). A stem \u0022may consist solely of a single root morpheme (i.e. a \u0027simple\u0027 stem as in ","Ws":"en"},{"Text":"man","Ws":"en","NamedStyle":"Emphasized Text"},{"Text":"), or of two root morphemes (e.g. a \u0027compound\u0027 stem, as in ","Ws":"en"},{"Text":"blackbird","Ws":"en","NamedStyle":"Emphasized Text"},{"Text":"), or of a root morpheme plus a derivational affix (i.e. a \u0027complex\u0027 stem, as in ","Ws":"en"},{"Text":"manly","Ws":"en","NamedStyle":"Emphasized Text"},{"Text":", ","Ws":"en"},{"Text":"unmanly","Ws":"en","NamedStyle":"Emphasized Text"},{"Text":", ","Ws":"en"},{"Text":"manliness","Ws":"en","NamedStyle":"Emphasized Text"},{"Text":"). All have in common the notion that it is to the stem that inflectional affixes are attached.\u0022 (Crystal, 1997:362)","Ws":"en"}]}}',NULL,NULL,0,NULL,'Guid_55');
